import freemarker.template.Configuration;
import freemarker.template.Template;
import freemarker.template.TemplateException;
import freemarker.template.TemplateExceptionHandler;
import org.apache.commons.lang3.StringUtils;
import org.apache.commons.lang3.Validate;

import java.io.IOException;
import java.io.StringWriter;
import java.util.HashMap;
import java.util.Map;

/**
 * Template rendering service for user profile pages.
 * Uses Freemarker template engine to render user-provided templates.
 */
public class TemplateService {

    private final Configuration freemarkerConfig;

    /**
     * Constructor initializes Freemarker configuration.
     */
    public TemplateService() {
        this.freemarkerConfig = createFreemarkerConfiguration();
    }

    /**
     * Renders user profile page based on provided username and template content.
     *
     * @param username        the username to be passed to the template
     * @param templateContent the Freemarker template content provided by user
     * @return rendered HTML string
     * @throws IllegalArgumentException if parameters are invalid
     * @throws TemplateProcessingException if template processing fails
     */
    public String renderUserProfile(String username, String templateContent) {
        // Validate input parameters
        Validate.notBlank(username, "Username must not be blank");
        Validate.notBlank(templateContent, "Template content must not be blank");

        // Sanitize username to prevent potential injection
        String sanitizedUsername = sanitizeInput(username);

        try {
            // Create template from string content
            Template template = new Template("userProfileTemplate", 
                                           templateContent, 
                                           freemarkerConfig);

            // Prepare data model
            Map<String, Object> dataModel = new HashMap<>();
            dataModel.put("username", sanitizedUsername);

            // Render template
            StringWriter writer = new StringWriter();
            template.process(dataModel, writer);

            return writer.toString();

        } catch (IOException e) {
            throw new TemplateProcessingException("Failed to process template", e);
        } catch (TemplateException e) {
            throw new TemplateProcessingException("Template syntax error", e);
        }
    }

    /**
     * Creates and configures Freemarker configuration.
     *
     * @return configured Freemarker Configuration instance
     */
    private Configuration createFreemarkerConfiguration() {
        Configuration cfg = new Configuration(Configuration.VERSION_2_3_31);

        // Configure for safe template processing
        cfg.setTemplateExceptionHandler(TemplateExceptionHandler.RETHROW_HANDLER);
        cfg.setLogTemplateExceptions(false);
        cfg.setWrapUncheckedExceptions(true);
        cfg.setFallbackOnNullLoopVariable(false);

        // Disable auto-escaping since we're handling HTML output
        cfg.setOutputEncoding("UTF-8");

        return cfg;
    }

    /**
     * Sanitizes input to prevent potential security issues.
     * Removes control characters and excessive whitespace.
     *
     * @param input the input string to sanitize
     * @return sanitized string
     */
    private String sanitizeInput(String input) {
        if (StringUtils.isBlank(input)) {
            return input;
        }

        // Remove control characters (except tab, newline, carriage return)
        String sanitized = input.replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "");

        // Trim and limit length to prevent abuse
        sanitized = StringUtils.trim(sanitized);
        if (sanitized.length() > 100) {
            sanitized = sanitized.substring(0, 100);
        }

        return sanitized;
    }

    /**
     * Custom exception for template processing errors.
     */
    public static class TemplateProcessingException extends RuntimeException {
        public TemplateProcessingException(String message) {
            super(message);
        }

        public TemplateProcessingException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
